def prune_messages(messages, max_tokens, token_counter):
    # Simple message list pruning helper
    total_tokens = sum([token_counter(m) for m in messages])
    while total_tokens > max_tokens and len(messages) > 1:
        removed = messages.pop(0)
        total_tokens -= token_counter(removed)
    return messages

